import { useMemo } from "react";
import { useNavigate } from "react-router-dom";
import { useSelector } from "react-redux";
import { adaptProduct } from "../utils/shopAdapters";
import { useLang } from "../context/LangContext";
import IconImg from "./IconImg";

function resolveImg(img) {
  if (Array.isArray(img)) return img[0] || "";
  return img || "";
}

export default function Hero() {
  const navigate = useNavigate();
  const { t } = useLang();
  const raw = useSelector((s) => s.products.products);
  const prods = useMemo(() => (raw || []).map(adaptProduct).filter(Boolean), [raw]);

  return (
    <div style={{ background: "linear-gradient(120deg,#111 0%,#2A2A2A 55%,#3D1825 100%)", color: "#fff", padding: "0 20px", position: "relative", overflow: "hidden" }}>
      <div className="hero-grid" style={{ maxWidth: 1280, margin: "0 auto", display: "grid", gridTemplateColumns: "1fr 1fr", alignItems: "center", minHeight: 320, gap: 40 }}>

        {/* Left copy */}
        <div style={{ padding: "44px 0" }}>
          <div style={{ background: "#D6247F", display: "inline-flex", alignItems: "center", gap: 8, borderRadius: 3, padding: "4px 12px", marginBottom: 16, fontSize: 11, fontFamily: "'Josefin Sans',sans-serif", fontWeight: 700, letterSpacing: ".08em", textTransform: "uppercase" }}>
            <IconImg name="fire" height={14} alt="" style={{ filter: "brightness(0) invert(1)" }} />
            Semaine Beauté — Économisez jusqu&apos;à 20%
          </div>
          <h1 style={{ fontFamily: "'Josefin Sans',sans-serif", fontSize: "clamp(28px,4.5vw,54px)", fontWeight: 700, lineHeight: 1.15, marginBottom: 14, whiteSpace: "pre-line", letterSpacing: ".02em" }}>{t.heroTitle}</h1>
          <p style={{ fontSize: 14, color: "#CCC", lineHeight: 1.8, marginBottom: 26, maxWidth: 400 }}>{t.heroSub}</p>
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
            <button type="button" className="btn-pink" onClick={() => navigate("/products")} style={{ padding: "12px 28px", fontSize: 13, letterSpacing: ".08em" }}>
              {t.shopNow}
            </button>
            <button
              type="button"
              style={{ background: "transparent", color: "#fff", border: "1.5px solid #666", borderRadius: 3, padding: "11px 24px", fontSize: 13, cursor: "pointer", fontFamily: "'Josefin Sans',sans-serif", fontWeight: 700, letterSpacing: ".06em", textTransform: "uppercase", transition: "border-color .2s" }}
              onMouseOver={(e) => { e.currentTarget.style.borderColor = "#fff"; }}
              onMouseOut={(e) => { e.currentTarget.style.borderColor = "#666"; }}
              onClick={() => navigate("/about")}
            >
              En savoir plus
            </button>
          </div>
          <p style={{ marginTop: 16, fontSize: 11, color: "#666", letterSpacing: ".04em" }}>*La vente se termine le 7 avril, jusqu'à épuisement des stocks.</p>
        </div>

        {/* Right product cards */}
        <div className="hero-visual" style={{ display: "flex", justifyContent: "center", alignItems: "center", gap: 14, flexWrap: "wrap", padding: "28px 0" }}>
          {prods.slice(0, 4).map((p) => {
            const imgSrc = resolveImg(p.img);
            return (
              <div
                key={p.id}
                style={{ background: "rgba(255,255,255,.07)", border: "1px solid rgba(255,255,255,.10)", borderRadius: 6, padding: "10px 8px", textAlign: "center", width: 100, backdropFilter: "blur(4px)", overflow: "hidden" }}
              >
                <div
                  className="shop-thumb"
                  style={{
                    width: 60,
                    height: 60,
                    margin: "0 auto 6px",
                    borderRadius: 4,
                    background: "rgba(255,255,255,.12)",
                    border: "1px solid rgba(255,255,255,.15)",
                  }}
                >
                  {imgSrc ? (
                    <img
                      src={imgSrc}
                      alt={p.name}
                      onError={(e) => { e.currentTarget.style.display = "none"; }}
                    />
                  ) : (
                    <IconImg name="heart" height={28} alt="" style={{ filter: "brightness(0) invert(1)", opacity: 0.9 }} />
                  )}
                </div>
                <div style={{ fontSize: 9, color: "#ddd", lineHeight: 1.4, fontFamily: "'Josefin Sans',sans-serif" }}>{p.name.split(" ").slice(0, 2).join(" ")}</div>
                {p.old && <div style={{ marginTop: 4, fontSize: 11, color: "#D6247F", fontWeight: 700 }}>-{Math.round((1 - p.price / p.old) * 100)}%</div>}
              </div>
            );
          })}
        </div>
      </div>

      {/* Dots */}
      <div style={{ textAlign: "center", paddingBottom: 14, display: "flex", justifyContent: "center", gap: 6 }}>
        {[1, 2, 3, 4, 5].map((i) => (
          <div key={i} style={{ width: i === 2 ? 10 : 8, height: i === 2 ? 10 : 8, borderRadius: "50%", background: i === 2 ? "#D6247F" : "rgba(255,255,255,.25)" }} />
        ))}
      </div>
    </div>
  );
}
